import { db } from '@mindstudio-ai/agent';

// MRA's container wrapping the platform's agent-thread primitive.
// Each Mr. A chat thread has one conversations row tying it to a user and (optionally) a project.
interface Conversation {
  userId: string;
  projectId?: string | null;                 // null for global / un-scoped threads
  agentThreadId: string;                     // Platform-provided thread id
  title: string;                             // Auto-generated by platform after first exchange
  lastMessageAt?: number;
  lastMessagePreview?: string;
  archived: boolean;
}

export const Conversations = db.defineTable<Conversation>('conversations', {
  defaults: {
    title: 'New thread',
    archived: false,
  },
});
